143→/**
144→ * Send daily briefs to multiple subscribers
145→ */
146→export async function sendDailyBriefsBatch(
147→  subscribers: Subscriber[],
148→  briefs: IdeaBrief[],
149→  config: EmailServiceConfig = {},
150→  options: {
151→    concurrency?: number;
152→    delayMs?: number;
153→    onProgress?: (completed: number, total: number) => void;
154→  } = {}
155→): Promise<BatchDeliveryResult> {
156→  const { concurrency = DEFAULT_EMAIL_CONCURRENCY, delayMs = DEFAULT_EMAIL_DELAY_MS, onProgress } = options;
157→
158→  const result: BatchDeliveryResult = {
159→    total: subscribers.length,
160→    sent: 0,
161→    failed: 0,
162→    deliveries: [],
163→  };
164→
165→  if (subscribers.length === 0) {
166→    return result;
167→  }
168→
169→  // Process in batches
170→  for (let i = 0; i < subscribers.length; i += concurrency) {
171→    const batch = subscribers.slice(i, i + concurrency);
172→
173→    const batchPromises = batch.map(subscriber =>
174→      sendDailyBrief(subscriber, briefs, config)
175→    );
176→
177→    const batchResults = await Promise.all(batchPromises);
178→
179→    for (const delivery of batchResults) {
180→      result.deliveries.push(delivery);
181→      if (delivery.status === 'sent') {
182→        result.sent++;
183→      } else {
184→        result.failed++;
185→      }
186→    }
187→
188→    // Progress callback
189→    if (onProgress) {
190→      const completed = Math.min(i + concurrency, subscribers.length);
191→      onProgress(completed, subscribers.length);
192→    }
193→
194→    // Rate limiting delay between batches
195→    if (i + concurrency < subscribers.length && delayMs > 0) {
196→      await new Promise(resolve => setTimeout(resolve, delayMs));
197→    }
198→  }
199→
200→  return result;
201→}
