  1→/**
  2→ * Pipeline Distributed Lock
  3→ *
  4→ * Uses Redis SET NX EX to prevent concurrent pipeline runs.
  5→ * When Redis is unavailable, falls back to a PostgreSQL advisory lock
  6→ * so concurrent runs are still prevented.
  7→ *
  8→ * IMPORTANT: The PG advisory lock fallback uses a dedicated single-connection
  9→ * client. Advisory locks are session-level — acquire and release MUST happen
 10→ * on the same connection. Using the main connection pool would cause the lock
 11→ * to stick permanently when release lands on a different pooled connection.
 12→ */
 13→
 14→import postgres from 'postgres';
 15→import { getRedisClient } from './redis';
 16→import { config } from '../config/env';
 17→
 18→const LOCK_KEY = 'pipeline:lock';
 19→const DEFAULT_TTL_SECONDS = 600; // 10 minutes
 20→export const PIPELINE_LOCK_TTL_SECONDS = DEFAULT_TTL_SECONDS;
 21→
 22→/**
 23→ * Fixed advisory lock key derived from the lock name.
 24→ * pg_try_advisory_lock takes a bigint — we use a stable hash.
 25→ */
 26→const ADVISORY_LOCK_KEY = 2_891_347_651; // arbitrary stable constant for 'pipeline:lock'
 27→
 28→// Lua script: DEL only when the stored value matches the caller's runId.
 29→// Prevents one run from accidentally releasing another run's lock.
 30→const RELEASE_SCRIPT = `
 31→if redis.call("get", KEYS[1]) == ARGV[1] then
 32→  return redis.call("del", KEYS[1])
 33→else
 34→  return 0
 35→end
 36→`;
 37→
 38→// Lua script: EXPIRE only when the stored value matches the caller's runId.
 39→// Prevents one run from extending another run's lock.
 40→const EXTEND_SCRIPT = `
 41→if redis.call("get", KEYS[1]) == ARGV[1] then
 42→  return redis.call("expire", KEYS[1], ARGV[2])
 43→else
 44→  return 0
 45→end
 46→`;
 47→
 48→/**
 49→ * Dedicated single-connection client for advisory lock operations.
 50→ * Guarantees acquire + release always hit the same PG session.
 51→ */
 52→let lockClient: ReturnType<typeof postgres> | null = null;
 53→
 54→function getLockClient(): ReturnType<typeof postgres> {
 55→  if (!lockClient) {
 56→    lockClient = postgres(config.databaseUrl, {
 57→      max: 1,
 58→      idle_timeout: 0,
 59→      connect_timeout: 10,
 60→      ssl: config.isProduction ? { rejectUnauthorized: false } : false,
 61→      prepare: false,
 62→    });
 63→  }
 64→  return lockClient;
 65→}
 66→
 67→/**
 68→ * Acquire a PostgreSQL session-level advisory lock.
 69→ * Uses a dedicated connection so release always targets the same session.
 70→ */
 71→async function acquireDbAdvisoryLock(): Promise<boolean> {
 72→  try {
 73→    const client = getLockClient();
 74→    const rows = await client`SELECT pg_try_advisory_lock(${ADVISORY_LOCK_KEY}) AS locked`;
 75→    return rows[0]?.locked === true;
 76→  } catch {
 77→    // DB unreachable — cannot lock, allow run (same as old Redis-absent behavior)
 78→    return true;
 79→  }
 80→}
 81→
 82→/**
 83→ * Release a PostgreSQL session-level advisory lock.
 84→ * Uses the same dedicated connection that acquired it.
 85→ */
 86→async function releaseDbAdvisoryLock(): Promise<void> {
 87→  try {
 88→    const client = getLockClient();
 89→    await client`SELECT pg_advisory_unlock(${ADVISORY_LOCK_KEY})`;
 90→  } catch {
 91→    // Best-effort — lock releases automatically when the session ends
 92→  }
 93→}
 94→
 95→/**
 96→ * Attempt to acquire the pipeline lock.
 97→ *
 98→ * @param runId   Unique value stored in the lock (used for safe release).
 99→ * @param ttlSeconds  Lock auto-expiry in seconds. Defaults to 600 (10 min).
100→ * @returns `true` if the lock was acquired, `false` if already held.
101→ *          Falls back to a PostgreSQL advisory lock when Redis is unavailable.
102→ */
103→export async function acquirePipelineLock(
104→  runId: string,
105→  ttlSeconds: number = DEFAULT_TTL_SECONDS,
106→): Promise<boolean> {
107→  const redis = getRedisClient();
108→  if (!redis) return acquireDbAdvisoryLock();
109→
110→  try {
111→    const result = await redis.set(LOCK_KEY, runId, 'EX', ttlSeconds, 'NX');
112→    return result === 'OK';
113→  } catch {
114→    // Redis unreachable — fall back to DB advisory lock
115→    return acquireDbAdvisoryLock();
116→  }
117→}
118→
119→/**
120→ * Release the pipeline lock, but only if it was acquired by the given runId.
121→ */
122→export async function releasePipelineLock(runId: string): Promise<void> {
123→  const redis = getRedisClient();
